module frequency_divider (
    input clk,
    input rst,
    output reg clk_out
);
    reg [2:0] obf_counter;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            obf_counter <= 3'b000;
            clk_out <= 0;
        end else begin
            obf_counter <= obf_counter + 1;
            if (obf_counter == 3'b111) begin
                clk_out <= ~clk_out;
                obf_counter <= 3'b000;
            end
        end
    end
endmodule
